(function(root,factory){if(typeof define==='function'&&define.amd){define([],factory);}else if(typeof exports==='object'){module.exports=factory();}else{root.Fountain=factory();}}(this,function(){
'use strict';
var Fountain=function(){};
Fountain.prototype={parse:function(script,withTokens){
var self=this;
self.tokens=[];
self.title_page=[];

// Normalize
script=script.replace(/\r\n/g,'\n').replace(/\r/g,'\n');
var lines=script.split('\n');
var tokens=[];

// Title page (key: value pairs before first blank line followed by content)
var inTitlePage=true;
var i=0;
while(inTitlePage&&i<lines.length){
  var l=lines[i].trim();
  if(l===''){inTitlePage=(i<3);i++;continue;}
  var kv=l.match(/^([A-Za-z ]+):\s*(.*)$/);
  if(kv){self.title_page.push({token:'title_page',key:kv[1].trim(),text:kv[2].trim()});i++;continue;}
  inTitlePage=false;
}

// Scene headings: INT./EXT./INT.EXT./I/E at line start, optionally after whitespace
var SCENE_HEADING=/^(INT\.|EXT\.|INT\/EXT\.|INT\.\/EXT\.|I\/E)\s+(.+?)(?:\s+-\s+(.+))?$/i;
// Character cue: line is ALL CAPS (with optional parens), surrounded by blank lines
var CHARACTER_CUE=/^([A-Z][A-Z0-9 _\-'\.]{0,39})(\s*\([^)]*\))?$/;
// Dual dialogue marker
var DUAL=/\s*\^\s*$/;
// Transition: ends with " TO:" or is FADE IN/OUT
var TRANSITION=/^(FADE (IN|OUT|TO BLACK)|.+ TO:)\s*$/i;
// Section / synopsis
var SECTION=/^(#{1,6})\s*(.+)$/;
var SYNOPSIS=/^={1}\s+(.+)$/;
// Centered: surrounded by >< or starts with >
var CENTERED=/^>\s*(.+)\s*<$/;
var NOTE=/^\[\[(.+?)\]\]$/;
var PAGE_BREAK=/^={3,}\s*$/;
var BONEYARD_START=/^\/\*/;
var BONEYARD_END=/\*\/$/;

var inBoneyard=false;
var pending=[];

function flush(){
  if(!pending.length)return;
  var block=pending.join('\n').trim();
  pending=[];
  return block||null;
}

function emit(type,text,opts){
  var tok=Object.assign({type:type,text:text||''},opts||{});
  tokens.push(tok);
}

var len=lines.length;
var j=i;
while(j<len){
  var raw=lines[j];
  var line=raw.trim();

  // Boneyard
  if(BONEYARD_START.test(line)){inBoneyard=true;}
  if(inBoneyard){if(BONEYARD_END.test(line))inBoneyard=false;j++;continue;}

  // Page break
  if(PAGE_BREAK.test(line)){flush();emit('page_break','');j++;continue;}

  // Note
  if(NOTE.test(line)){flush();emit('note',line.replace(NOTE,'$1'));j++;continue;}

  // Section
  if(SECTION.test(line)){flush();var sm=line.match(SECTION);emit('section',sm[2],{depth:sm[1].length});j++;continue;}

  // Synopsis
  if(SYNOPSIS.test(line)){flush();emit('synopsis',line.replace(SYNOPSIS,'$1'));j++;continue;}

  // Centered action
  if(CENTERED.test(line)){flush();emit('centered',line.replace(CENTERED,'$1'));j++;continue;}

  // Transition
  if(TRANSITION.test(line)&&(j===0||lines[j-1].trim()==='')){
    flush();emit('transition',line);j++;continue;
  }

  // Forced scene heading with "."
  if(line.charAt(0)==='.'&&line.charAt(1)!=='.'){
    flush();
    var forced=line.slice(1).trim();
    var fm=forced.match(/^(.+?)(?:\s+-\s+(.+))?$/);
    emit('scene_heading',forced,{location:(fm&&fm[1])||forced,time_of_day:(fm&&fm[2])||null,scene_number:null});
    j++;continue;
  }

  // Scene heading
  if(SCENE_HEADING.test(line)){
    flush();
    var shm=line.match(SCENE_HEADING);
    emit('scene_heading',line,{location:(shm[2]||'').trim(),time_of_day:(shm[3]||null),scene_number:null});
    j++;continue;
  }

  // Character cue (blank line before, blank line or parenthetical after)
  var prevBlank=(j===0||lines[j-1].trim()==='');
  var nextLine=(j+1<len)?lines[j+1].trim():'';
  var isDual=DUAL.test(line);
  var cleanCue=line.replace(DUAL,'').trim();

  if(prevBlank&&CHARACTER_CUE.test(cleanCue)&&nextLine!==''){
    flush();
    var cueM=cleanCue.match(CHARACTER_CUE);
    var charName=(cueM[1]||'').trim();
    var extension=cueM[2]?cueM[2].trim():null;
    emit('character',charName,{dual:isDual,extension:extension});
    j++;
    // Consume dialogue + parentheticals
    while(j<len&&lines[j].trim()!==''){
      var dl=lines[j].trim();
      if(/^\(/.test(dl)&&/\)$/.test(dl)){
        emit('parenthetical',dl.slice(1,-1));
      } else {
        emit('dialogue',dl);
      }
      j++;
    }
    continue;
  }

  // Blank line — flush action accumulator
  if(line===''){
    var block=flush();
    if(block)emit('action',block);
    j++;continue;
  }

  // Action
  pending.push(line.charAt(0)==='!'?raw.slice(1):raw);
  j++;
}
// Flush final action block
var last=flush();
if(last)emit('action',last);

self.tokens=tokens;

// Build html (lightweight — consumers use tokens directly)
var html='';
var title='';
for(var k=0;k<self.title_page.length;k++){
  if(self.title_page[k].key.toLowerCase()==='title'){title=self.title_page[k].text;break;}
}

if(withTokens){return {title:title,html:{title_page:'',script:html},tokens:tokens};}
return {title:title,html:{title_page:'',script:html}};
}};
return Fountain;
}));
